final:
module priority_arbiter(
    input wire req0, 
    input wire req1, 
    input wire req2, 
    input wire req3, 
    output reg [3:0] obf_grant
);
    always @(*) begin
        if (req0)
            obf_grant = 4'b0001; // obf_grant req0
        else if (req1)
            obf_grant = 4'b0010; // obf_grant req1
        else if (req2)
            obf_grant = 4'b0100; // obf_grant req2
        else if (req3)
            obf_grant = 4'b1000; // obf_grant req3
        else
            obf_grant = 4'b0000; // no request
    end
endmodule
